#include<bits/stdc++.h>
using namespace std;
int s,n,m;
int a[105][105],dp[20010];
int main()
{
    scanf("%d%d%d",&s,&n,&m);
    for(int i=1;i<=s;i++)
    {
        for(int j=1;j<=n;j++)
        {
            scanf("%d",&a[j][i]);
        }
    }
    for(int i=1;i<=n;i++)
    {
        sort(a[i]+1,a[i]+1+s);
        for(int j=1;j<=s;j++)
        {
            a[i][j]*=2;
            a[i][j]++;
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=m;j>=1;j--)
        {
            for(int k=1;k<=s;k++)
            {
                if(j>=a[i][k])
                {
                    dp[j]=max(dp[j],dp[j-a[i][k]]+i*k);
                }
            }
        }
    }
    printf("%d",dp[m]);
    return 0;
}
